'use client';

import { useEffect, useState } from 'react';
import { Eye, EyeOff } from 'lucide-react';

export default function Home() {
  const [password, setPassword] = useState('');
  const [result, setResult] = useState('');
  const [score, setScore] = useState(0);
  const [suggestions, setSuggestions] = useState<string[]>([]);
  const [showPassword, setShowPassword] = useState(false);
  const [showHints, setShowHints] = useState(false);

  const checkPassword = async () => {
    const res = await fetch('/api/check-password', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ password })
    });

    const data = await res.json();
    setResult(data.strength);
    setScore(data.score);
    setSuggestions(data.suggestions);
  };

  const getColor = () => {
    if (result === 'Gyenge') return 'bg-red-500';
    if (result === 'Közepes') return 'bg-yellow-500';
    if (result === 'Erős') return 'bg-green-500';
    return 'bg-gray-300';
  };

  const getTextColor = () => {
    if (result === 'Gyenge') return 'text-red-500';
    if (result === 'Közepes') return 'text-yellow-500';
    if (result === 'Erős') return 'text-green-500';
    return 'text-black';
  };

  useEffect(() => {
    if (result === 'Gyenge') setShowHints(true);
  }, [result]);

  return (
    <div className="flex items-center justify-center h-screen bg-gray-100">
      <div className="bg-white p-8 rounded-xl shadow-lg text-center w-[300px]">
        <h1 className="text-xl font-bold mb-4">Jelszó erősség</h1>

        <form
          onSubmit={(e) => {
            e.preventDefault();
            checkPassword();
          }}
          className="flex flex-col gap-3"
        >
          <div className="relative">
            <input
              type={showPassword ? 'text' : 'password'}
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              placeholder="Írd be a jelszót"
              className="p-2 border rounded-lg w-full pr-10"
            />

            <button
              type="button"
              onClick={() => setShowPassword(!showPassword)}
              className="absolute right-2 top-1/2 -translate-y-1/2 text-gray-500 hover:cursor-pointer"
            >
              {showPassword ? <EyeOff size={18} /> : <Eye size={18} />}
            </button>
          </div>
        </form>

        <div className="w-full h-2 bg-gray-200 rounded mt-4 overflow-hidden">
          <div
            className={`h-full transition-all duration-300 ${getColor()}`}
            style={{ width: `${score * 25}%` }}
          />
        </div>

        {result && (
          <p className={`mt-3 font-bold ${getTextColor()}`}>
            {result}
          </p>
        )}
        <button
          onClick={() => setShowHints(!showHints)}
          className="mt-2 text-sm text-blue-500 hover:underline hover:cursor-pointer"
        >
          {showHints
            ? 'Hint elrejtése'
            : 'Hogyan tehetném erősebbé a jelszavam?'}
        </button>
        {showHints && suggestions.length > 0 && (
          <div className="mt-4 bg-gray-50 border rounded-lg p-3 text-left">
            <p className="text-sm font-semibold mb-2 text-gray-700">
              Tippek:
            </p>

            <ul className="space-y-1 text-sm text-gray-600">
              {suggestions.map((s, i) => (
                <li key={i} className="flex items-start gap-2">
                  <span className="text-blue-500">•</span>
                  <span>{s}</span>
                </li>
              ))}
            </ul>
          </div>
        )}
      </div>
    </div>
  );
}